insert into public.word_survivor_terms (id, term, meaning, example_sentence, level, type) values
  ('6fcc0849-8766-45b8-b537-64f7936127e4', 'happy', '''Happy'' describes a feeling of joy.', 'She is very happy today; she can''t stop smiling.', 'A1', 'vocabulary'),
  ('3cb93ef6-00a3-4f28-885d-382dcc74a7ad', 'hot', '''Hot'' describes temperature.', 'The soup is too hot — I can''t eat it.', 'A1', 'vocabulary'),
  ('c1f55d04-d0aa-4803-84d0-9ff5d4682912', 'good', '''Good'' describes quality or behaviour.', 'He is a good student; he always does his homework.', 'A1', 'vocabulary'),
  ('4960ac57-7ce9-43e9-b3cf-46cb43236c6f', 'rainy', '''Rainy'' describes weather with rain.', 'The weather is rainy today, so we need an umbrella.', 'A1', 'vocabulary'),
  ('8bb17a3b-6900-4ddc-885f-6e618c89b8a1', 'tired', '''Tired'' means you need rest.', 'I feel tired ; I need to sleep.', 'A1', 'vocabulary'),
  ('559d9181-48c1-45b0-8e4c-99de8c609f14', 'turn down', '''Turn down'' means to reduce the volume.', 'Please turn down the TV; it''s too loud.', 'A1', 'phrasal_verb'),
  ('0e89c79c-9815-4789-8097-792890704525', 'take off', '''Take off'' means to remove.', 'Can you take off your shoes before coming in?', 'A1', 'phrasal_verb'),
  ('a3d04f20-1013-4939-ba0a-7a3d2c2fb620', 'wake up', '''Wake up'' means to stop sleeping.', 'I always wake up at 7 a.m.', 'A1', 'phrasal_verb'),
  ('755b6e59-4f1d-4a58-9b43-845fb18e357b', 'turn on', '''Turn on'' means to start/activate something.', 'Could you turn on the lights? It''s dark.', 'A1', 'phrasal_verb'),
  ('abfa37ad-bcca-4b79-a66e-e83ebcbbcbf3', 'go out', '''Go out'' means to leave the house for an activity.', 'Let''s go out for a walk in the park.', 'A1', 'phrasal_verb'),
  ('0f97472e-589b-494d-9699-ec35e72b593f', 'have', 'We say ''have breakfast/lunch/dinner''.', 'I usually have breakfast at 7 a.m.', 'A1', 'collocation'),
  ('938e1f87-c67b-40b2-a428-f6421d348881', 'take', 'We say ''take photos''.', 'She likes to take photos on her phone.', 'A1', 'collocation'),
  ('98a0b08b-543e-4ecc-adfe-5725b1762e6e', 'do', 'We say ''do homework''.', 'Did you do your homework?', 'A1', 'collocation'),
  ('1ebc6233-8e06-43d3-af26-42535a6f1171', 'make', 'We say ''make friends''.', 'He wants to make friends with everyone.', 'A1', 'collocation'),
  ('77029b9a-bd0a-4ff7-9433-d866c0102d4e', 'goes', 'Present simple, third person singular adds -s: ''goes''.', 'She goes to school every day.', 'A1', 'grammar'),
  ('b4742fa2-0f25-4849-80be-f5410e2594b3', 'read', 'Past simple: ''read'' (yesterday).', 'I read a book yesterday.', 'A1', 'grammar'),
  ('09e4e3d0-bedf-4ade-b853-c2c6c5faba35', 'are', 'Present continuous with ''they'' uses ''are''.', 'They are watching TV right now.', 'A1', 'grammar'),
  ('c14fb219-342c-4d3b-89f5-6dae7db63d71', 'is', '''There is'' is used with singular nouns.', 'There is a cat in the garden.', 'A1', 'grammar'),
  ('2667f8b3-0575-451c-97b3-dabf36296f12', 'interesting', '''Interesting'' means it captures your attention.', 'The museum was interesting ; we learned a lot.', 'A2', 'vocabulary'),
  ('cc4a5e05-5c4a-48e7-b8cf-f5fcb0fec288', 'disappointed', '''Disappointed'' means sad because something didn''t go well.', 'He was disappointed when his team lost the match.', 'A2', 'vocabulary'),
  ('3451eed4-0c02-4757-ba36-a07c8c0a4997', 'difficult', '''Difficult'' means hard to do.', 'This exercise is too difficult for beginners — they need more practice first.', 'A2', 'vocabulary'),
  ('6e649d73-c09e-45c8-90b5-df00b4d05518', 'nervous', '''Nervous'' describes feeling worried or anxious.', 'She was very nervous about her exam results.', 'A2', 'vocabulary'),
  ('2fc4dc7b-7bb1-4e0a-9482-b91346d438e4', 'moving', '''Moving'' means it makes you feel strong emotion.', 'The film was so moving that I almost cried.', 'A2', 'vocabulary'),
  ('6c3fc1af-065b-4c63-a089-b0cf87524160', 'look after', '''Look after'' means to take care of.', 'Can you look after my dog while I''m away?', 'A2', 'phrasal_verb'),
  ('9678ffae-a10e-4e6d-90d6-3c04b6cf2a9d', 'look for', '''Look for'' means to search for something.', 'I need to look for my keys; I can''t find them.', 'A2', 'phrasal_verb'),
  ('ee4c0718-64d2-4778-a69b-a8e8d0cbc678', 'take up', '''Take up'' means to start a new activity or hobby.', 'She decided to take up French this year.', 'A2', 'phrasal_verb'),
  ('4457ca21-1b67-4e08-a79e-31a1d81d1226', 'give up', '''Give up'' means to stop trying.', 'Don''t give up ! You can do it.', 'A2', 'phrasal_verb'),
  ('7bf36d5c-063d-4f14-a106-a25b10fc2954', 'get on', '''Get on'' a vehicle means to enter it.', 'We need to get on the bus at the next stop.', 'A2', 'phrasal_verb'),
  ('1c0e71d4-e224-4a84-98f1-575ceb21f643', 'take', 'We say ''take care of''.', 'It''s important to take care of your health.', 'A2', 'collocation'),
  ('dbb3288f-c3a4-4f18-9dd0-7a102d521742', 'does', 'We say ''do your best''.', 'He always does his best in exams.', 'A2', 'collocation'),
  ('8a53ab89-33fd-495a-9e02-8c021f6ccdad', 'had', 'We say ''have a party''.', 'They had a party for her birthday.', 'A2', 'collocation'),
  ('0f029ee6-7769-4e26-ba3c-8ecc9a2a298b', 'make', 'We say ''make a decision''.', 'I need to make a decision soon.', 'A2', 'collocation'),
  ('07c37638-fccd-44ed-bdc5-3d71a8b9fc1a', 'rains', 'First conditional: If + present simple, will + infinitive.', 'If it rains tomorrow, we will stay home.', 'A2', 'grammar'),
  ('5562a5be-eaf2-451f-9b3e-0edd7cf5954f', 'goes', 'Present simple with ''she'' needs -s: ''goes''.', 'She goes to the gym twice a week.', 'A2', 'grammar'),
  ('08726cc8-fda7-4d50-9cc6-8a5b3cb6ad74', 'were having', 'Past continuous for an action in progress when something else happened.', 'We were having dinner when the phone rang.', 'A2', 'grammar'),
  ('9c847098-0cb3-4d9d-8e78-bdd927bf2345', 'will have finished', 'Future perfect for an action completed before a future point.', 'By next year, she will have finished her studies.', 'A2', 'grammar'),
  ('f65e78f3-0667-4591-88cc-1b9f354f58ad', 'cramped', '''Cramped'' means there is not enough space.', 'The hotel room was very cramped — there was barely space for the bed.', 'B1', 'vocabulary'),
  ('7e52c3be-fc90-46c1-8fb2-0ec66b92debd', 'exhausted', '''Exhausted'' means extremely tired.', 'I was so exhausted after the long flight that I fell asleep immediately.', 'B1', 'vocabulary'),
  ('6299f511-e7f5-4ddc-afbf-2d6f81247c0b', 'interrupt', '''Interrupt'' means to start talking while someone else is already speaking.', 'It''s rude to interrupt someone while they are speaking.', 'B1', 'vocabulary'),
  ('63fe4d45-d2b0-4f56-a012-d4c48fce83bb', 'confusing', '''Confusing'' means difficult to understand.', 'The instructions were so confusing that nobody understood what to do.', 'B1', 'vocabulary'),
  ('922373cf-e865-48e5-acc0-c485411bea86', 'blunt', '''Blunt'' means very direct, sometimes rude.', 'She gave a blunt answer — short and not very polite.', 'B1', 'vocabulary'),
  ('91e8a7d2-d713-4912-ae29-521631a0162b', 'turn down', '''Turn down'' means to reduce volume, heat, etc.', 'Can you turn down the music? It''s too loud.', 'B1', 'phrasal_verb'),
  ('42e69d7a-ffb0-4666-9582-4da5f87b9079', 'fill in', '''Fill in'' a form means to complete it with information.', 'I need to fill in this form before Friday.', 'B1', 'phrasal_verb'),
  ('ef8f281b-486a-4ab6-b7d4-83bbe4054f35', 'give up', '''Give up'' means to stop doing something.', 'She decided to give up smoking last year.', 'B1', 'phrasal_verb'),
  ('ab79c64e-756e-4e56-a990-c53742a4ea4e', 'take off', '''Take off'' clothing/shoes means to remove them.', 'Please take off your shoes before entering the house.', 'B1', 'phrasal_verb'),
  ('9792ab4a-25f2-4d06-8415-a7f0975793df', 'make out', '''Make out'' means to manage to hear or see something clearly.', 'I couldn''t make out what he was saying — too much noise around.', 'B1', 'phrasal_verb'),
  ('4069d104-0110-4d59-b39c-1a515301c532', 'make', 'We say ''make a good impression'', not ''do''.', 'It''s important to make a good impression in a job interview.', 'B1', 'collocation'),
  ('dab579ae-4e6d-4031-8dec-96e44969a81a', 'take', 'We say ''take a risk''.', 'He decided to take a risk and start his own business.', 'B1', 'collocation'),
  ('c727a613-4dfd-4e0c-b4fb-93903b678325', 'do', 'We say ''do someone a favor''.', 'Could you do me a favor?', 'B1', 'collocation'),
  ('3ef0245f-ccdc-435d-9fd2-66a2823ca74f', 'pay', 'We say ''pay attention''.', 'I always pay attention to small details.', 'B1', 'collocation'),
  ('2ea5adc9-744d-4f2a-8a16-f3872cfbcade', 'had', 'Second conditional: If + past simple, would + infinitive.', 'If I had more time, I would learn French.', 'B1', 'grammar'),
  ('b1cf28f6-7c9d-4358-9a50-7f6dc85a03d6', 'has lived', 'Present perfect for actions that started in the past and continue now.', 'She has lived in this city since 2015.', 'B1', 'grammar'),
  ('e0d3d2e5-ff40-4863-8cee-677cde05c5fd', 'had started', 'Past perfect for an action completed before another past action.', 'By the time we arrived, the movie had started already.', 'B1', 'grammar'),
  ('04ea04c8-0415-48c5-9a73-7ef1cb50654f', 'mustn''t', '''Mustn''t'' expresses a strong prohibition.', 'You mustn''t smoke in here — it''s strictly forbidden.', 'B1', 'grammar'),
  ('484de9ef-ca98-4fff-b1ad-e7cfbc78adef', 'flawed', '''Flawed'' means containing a fault or weakness.', 'His argument was completely flawed; it had no logical basis at all.', 'B2', 'vocabulary'),
  ('ab63053a-af56-4559-ba1b-814b9d46d91b', 'recover', '''Recover'' means to return to a normal or better state.', 'After months of decline, sales finally started to recover again.', 'B2', 'vocabulary'),
  ('a31a0238-ec44-4471-a2b5-482c48311c94', 'composed', '''Composed'' means calm and in control of one''s emotions.', 'She remained remarkably composed despite the chaos around her.', 'B2', 'vocabulary'),
  ('8345bc6c-27f8-4f6c-906c-4f1864d329fb', 'impulsive', '''Impulsive'' means done suddenly without planning.', 'It was a impulsive decision — made without any real thought.', 'B2', 'vocabulary'),
  ('0e698784-20bd-47d5-8fa1-9d93ccaac986', 'intricate', '''Intricate'' means very complicated or detailed.', 'The novel''s plot is incredibly intricate, full of unexpected twists.', 'B2', 'vocabulary'),
  ('f443a3ca-ffda-4293-a310-cb8646802fc0', 'broke down', '''Break down'' (negotiations) means to fail.', 'The negotiations finally broke down after months of disagreement.', 'B2', 'phrasal_verb'),
  ('e063e45c-4375-4cf5-a128-0de6962cdf87', 'puts off', '''Put off'' means to postpone or delay.', 'He always puts off his work until the last minute.', 'B2', 'phrasal_verb'),
  ('7ec61798-b481-4155-b86d-246fd49b6bf1', 'get over', '''Get over'' means to recover from or overcome something.', 'She managed to get over her fear of public speaking.', 'B2', 'phrasal_verb'),
  ('cb3745ef-2375-4577-9356-698854360ee3', 'lay off', '''Lay off'' means to dismiss employees, usually for financial reasons.', 'The company had to lay off several employees due to budget cuts.', 'B2', 'phrasal_verb'),
  ('c865c662-15e5-450c-aafd-62521979f5a8', 'put up with', '''Put up with'' means to tolerate.', 'I can''t put up with his constant complaining anymore.', 'B2', 'phrasal_verb'),
  ('0f27c6a6-39e1-4d89-86e8-e414f3a735b5', 'face', 'We say ''face the consequences''.', 'He decided to face the consequences of his actions.', 'B2', 'collocation'),
  ('413605f1-c1da-49b0-be27-200af8703d91', 'make', 'We say ''make a choice/decision''.', 'She had to make a difficult choice between two job offers.', 'B2', 'collocation'),
  ('466ef4d7-bc44-451f-b12a-d3b4f4d96caf', 'hold', 'We say ''hold a press conference/meeting''.', 'The CEO will hold a press conference tomorrow morning.', 'B2', 'collocation'),
  ('703b25f8-84c8-405f-8016-72ead17fd62d', 'had studied', 'Past wishes use ''wish + had + past participle''.', 'I wish I had studied harder for the exam; I would have passed.', 'B2', 'grammar'),
  ('d5f60afe-31b3-4c8f-99ee-2a1a6ce46319', 'was he', 'Inversion is required after ''Not only'' at the start of a sentence.', 'Not only was he late, but he also forgot the documents.', 'B2', 'grammar'),
  ('5c74b3f3-ddee-438d-bb44-588d8cd790b3', 'must be finished', 'Modal passive: must + be + past participle.', 'The report must be finished by the team before the deadline.', 'B2', 'grammar'),
  ('0a1d9f03-0af6-43af-89e4-58ecb5b48764', 'had', '''Hardly had... when'' is an inverted structure for a sequence of past events.', 'Hardly had the meeting started when the fire alarm rang.', 'B2', 'grammar'),
  ('f0815856-a4e0-4c42-be79-8bde37c24fe7', 'convoluted', '''Convoluted'' means extremely complex and difficult to follow.', 'His speech was so convoluted that even experts struggled to follow his argument.', 'C1', 'vocabulary'),
  ('029f0917-f898-455d-a511-556ad2afc7a5', 'unflinching', '''Unflinching'' means not avoiding something difficult or unpleasant.', 'The critic praised the film for its unflinching portrayal of war.', 'C1', 'vocabulary'),
  ('6abe66c1-31e9-4b1c-80cd-925d9c5a5597', 'tactless', '''Tactless'' means lacking sensitivity in dealing with others.', 'Her tactless remarks during the meeting offended several colleagues.', 'C1', 'vocabulary'),
  ('711e9e4a-a180-4156-9bc3-06347f23dbbc', 'incontrovertible', '''Incontrovertible'' means impossible to deny or dispute.', 'The evidence was incontrovertible; no reasonable person could doubt his guilt.', 'C1', 'vocabulary'),
  ('d0be0ec5-49bd-4db9-962b-2f16cb5ff9f5', 'propensity', '''Propensity'' means a natural tendency to behave in a particular way.', 'He has a propensity for exaggeration that makes his stories hard to believe.', 'C1', 'vocabulary'),
  ('b0c9a585-8ae7-408f-bf9e-138330d741ea', 'boiled over', '''Boil over'' means a tense situation suddenly becomes an open conflict.', 'Tensions between the two countries finally boiled over into open conflict.', 'C1', 'phrasal_verb'),
  ('cfd66b16-c169-4ba8-9cf3-d0a1aaacb955', 'paper over', '''Paper over'' a problem means to hide it temporarily instead of solving it.', 'Critics say the policy will only paper over the underlying problem rather than solve it.', 'C1', 'phrasal_verb'),
  ('3ef04310-a690-4d97-9c27-c3cbbdf8b53c', 'press ahead', '''Press ahead (with)'' means to continue determinedly.', 'The board decided to press ahead with the merger despite shareholder objections.', 'C1', 'phrasal_verb'),
  ('90a27e87-19e0-4bc8-85aa-5868427867bb', 'claw', '''Claw back'' means to gradually and with effort regain something lost.', 'After the scandal, the senator struggled to claw back public trust.', 'C1', 'phrasal_verb'),
  ('c7f9cc96-5839-4886-8c13-85e62464c6c2', 'play', '''Play down'' means to make something seem less important than it is.', 'The minister tried to play down speculation about a cabinet reshuffle.', 'C1', 'phrasal_verb'),
  ('aeb28752-20ea-44b8-a0d8-aee4678f853c', 'heavy', 'We say ''come under heavy fire'' (be strongly criticized).', 'The government''s new policy has come under heavy fire from opposition parties.', 'C1', 'collocation'),
  ('6d98dac5-4931-42bc-a9b9-7b3d1469b610', 'unanimous', '''Unanimous decision'' means everyone agreed.', 'The committee reached a unanimous decision after hours of debate.', 'C1', 'collocation'),
  ('82b1a0ec-cb3e-48ab-b2c3-5acf42083dea', 'widespread', 'We say ''widespread skepticism/criticism''.', 'His proposal was met with widespread skepticism by the board.', 'C1', 'collocation'),
  ('fe042835-a85a-437f-ae41-83a16d29419d', 'join', '''Join forces'' means to work together.', 'The two companies are expected to join forces to compete with larger rivals.', 'C1', 'collocation'),
  ('f88056b8-cc5f-4fb1-9f84-62da76df9149', 'Despite', '''Despite'' is followed by a noun phrase, not a clause.', 'Despite the heavy rain, the match went ahead as planned.', 'C1', 'grammar'),
  ('54743f65-1932-41dd-98c5-f52db1c72461', 'would have', 'Inverted third conditional: ''Were it not for X, ... would have + past participle''.', 'Were it not for his support, the project would have failed.', 'C1', 'grammar'),
  ('ad7dba6f-7aaa-4b27-81c8-91a19da8b0d1', 'be', 'Subjunctive mood after ''essential that'': base form ''be'', no -s.', 'It is essential that the report be submitted by Friday.', 'C1', 'grammar'),
  ('b2c20fc3-f156-4c7d-8ea7-b2f3aa254e88', 'had', '''Scarcely had... when'' is an inverted structure similar to ''hardly had''.', 'Scarcely had the announcement been made when shares began to fall.', 'C1', 'grammar'),
  ('1f0747f2-9c73-4ff2-ab59-a53feaa7690c', 'predilection', '''Predilection'' means a preference or special liking for something.', 'His predilection for detail bordered on obsession.', 'C2', 'vocabulary'),
  ('d33f8d46-7fc7-4617-8af9-23e2261c4dac', 'irrefutable', '''Irrefutable'' means impossible to prove wrong.', 'The professor''s argument was irrefutable ; not a single point was open to dispute.', 'C2', 'vocabulary'),
  ('e42d3a82-222c-47bb-8fb3-e6f46da70c83', 'scintillating', '''Scintillating'' means brilliantly clever and lively.', 'Her scintillating wit made her the most entertaining person at the dinner.', 'C2', 'vocabulary'),
  ('04efbcf5-0cfd-4177-94c2-17230abe44f0', 'undercurrent', '''Undercurrent'' refers to a hidden feeling beneath the surface.', 'The negotiations were marked by a undercurrent of mutual distrust.', 'C2', 'vocabulary'),
  ('df895a0c-5eda-4fa7-a1fc-c1f4f265042c', 'impervious', '''Impervious'' means not affected or influenced by something.', 'He remained utterly impervious to their pleas for clemency.', 'C2', 'vocabulary'),
  ('616ff38c-7e7e-4dab-a87b-51950a10fef9', 'muck', '''Muck up'' (informal) means to spoil or ruin something.', 'Her offhand remark threatened to muck up months of delicate negotiation.', 'C2', 'phrasal_verb'),
  ('ba5fc91a-5bf3-49d6-a480-b906415a65fb', 'trade', '''Trade on'' means to take advantage of something for personal benefit.', 'He has always managed to trade on his natural charm rather than hard work.', 'C2', 'phrasal_verb'),
  ('525d2c41-e841-4fb6-b785-721d610d5e70', 'step', '''Step down'' means to resign from a position.', 'The minister was forced to step down following the scandal.', 'C2', 'phrasal_verb'),
  ('0002622a-a14b-4d42-b339-b581b1010a36', 'boiled', '''Boil over'' means suppressed emotion suddenly bursts out.', 'Years of pent-up frustration finally boiled over during the meeting.', 'C2', 'phrasal_verb'),
  ('c9fc945f-569e-44d4-81d9-9af87278b17c', 'browbeaten', '''Browbeaten into'' means forced through intimidation.', 'She would not be browbeaten into revealing her sources.', 'C2', 'phrasal_verb'),
  ('c8f60035-4c4e-415a-924f-45027cc15c26', 'lend', '''Lend credence to'' means to make something seem more believable.', 'The findings lend credence to the theory.', 'C2', 'collocation'),
  ('3ce7b6ae-ad48-4f6f-baf5-e44a8bd958ce', 'common', '''Common ground'' means a shared basis for agreement.', 'The two leaders finally found common ground after lengthy talks.', 'C2', 'collocation'),
  ('c470167a-7026-4476-b9cd-53e337a31061', 'scathing', '''Scathing criticism'' means severely critical.', 'His tactics drew scathing criticism from across the political spectrum.', 'C2', 'collocation'),
  ('fa2a6676-ed38-4ea4-ac16-807adebab3d4', 'yield', '''Yield'' means to produce or result in something.', 'The merger is expected to yield significant synergies.', 'C2', 'collocation'),
  ('6b1bd624-31dd-420e-8927-58059cd8b98c', 'has', 'Inversion with ''Rarely'' + has/have + past participle.', 'Rarely has such unanimity been seen in parliament.', 'C2', 'grammar'),
  ('edb28145-ca17-485f-a271-f59d304219e7', 'No sooner', '''No sooner... than'' is the correct inverted pairing (not ''when'').', 'No sooner had she finished speaking than the audience erupted into applause.', 'C2', 'grammar'),
  ('af7b0dc5-e4e7-4c3e-81c9-252ccffcf4a6', 'that', 'Cleft sentence: ''It was not until... that...''.', 'It was not until much later that the truth came to light.', 'C2', 'grammar'),
  ('582b193d-e14f-4ee7-bdea-772423ae8496', 'heeded', 'Inverted third conditional: ''Had + subject + past participle...''.', 'Had the committee heeded the warnings, the crisis might have been averted.', 'C2', 'grammar');
insert into public.word_survivor_questions (id, term_id, level, type, difficulty, prompt, options, correct_index, tip, tags) values
  ('51992a56-5e1f-463b-9c5d-b5e1ecd9f522', '6fcc0849-8766-45b8-b537-64f7936127e4', 'A1', 'vocabulary', 1, 'She is very ___ today; she can''t stop smiling.', '["happy","table","quickly","yesterday"]'::jsonb, 0, '''Happy'' describes a feeling of joy.', ARRAY['a1','vocabulary']::text[]),
  ('03087ae1-463e-45ec-ad5e-f57a20602782', '3cb93ef6-00a3-4f28-885d-382dcc74a7ad', 'A1', 'vocabulary', 1, 'The soup is too ___ — I can''t eat it.', '["hot","run","blue","eight"]'::jsonb, 0, '''Hot'' describes temperature.', ARRAY['a1','vocabulary']::text[]),
  ('7429ba42-1cd5-4159-9b5f-9bb2dc7508a5', 'c1f55d04-d0aa-4803-84d0-9ff5d4682912', 'A1', 'vocabulary', 1, 'He is a ___ student; he always does his homework.', '["good","table","slowly","green"]'::jsonb, 0, '''Good'' describes quality or behaviour.', ARRAY['a1','vocabulary']::text[]),
  ('947bf8bc-bb73-45cc-bdee-34fe5b67a00c', '4960ac57-7ce9-43e9-b3cf-46cb43236c6f', 'A1', 'vocabulary', 1, 'The weather is ___ today, so we need an umbrella.', '["rainy","hungry","expensive","friendly"]'::jsonb, 0, '''Rainy'' describes weather with rain.', ARRAY['a1','vocabulary']::text[]),
  ('bf55cdec-d541-47ee-955e-9eb542e38fa2', '8bb17a3b-6900-4ddc-885f-6e618c89b8a1', 'A1', 'vocabulary', 1, 'I feel ___ ; I need to sleep.', '["tired","excited","angry","surprised"]'::jsonb, 0, '''Tired'' means you need rest.', ARRAY['a1','vocabulary']::text[]),
  ('eac91e79-f76a-42e2-98b9-b480f669e47b', '559d9181-48c1-45b0-8e4c-99de8c609f14', 'A1', 'phrasal_verb', 1, 'Please ___ the TV; it''s too loud.', '["turn down","turn into","look up","give up"]'::jsonb, 0, '''Turn down'' means to reduce the volume.', ARRAY['a1','phrasal_verb']::text[]),
  ('43612c6d-e898-40c6-a66a-4a40ab8f95d5', '0e89c79c-9815-4789-8097-792890704525', 'A1', 'phrasal_verb', 1, 'Can you ___ your shoes before coming in?', '["take off","take up","look up","give up"]'::jsonb, 0, '''Take off'' means to remove.', ARRAY['a1','phrasal_verb']::text[]),
