  ('260e2600-f87b-4a87-bf06-8fca239adc6e', 'd5f60afe-31b3-4c8f-99ee-2a1a6ce46319', 'B2', 'grammar', 3, 'Not only ___ late, but he also forgot the documents.', '["he was","was he","he is","is he"]'::jsonb, 1, 'Inversion is required after ''Not only'' at the start of a sentence.', ARRAY['b2','grammar']::text[]),
  ('2041e7d7-2915-42f5-9bc1-1bedec3939c2', '5c74b3f3-ddee-438d-bb44-588d8cd790b3', 'B2', 'grammar', 3, 'The report ___ by the team before the deadline.', '["must finish","must be finished","must have finished","must been finished"]'::jsonb, 1, 'Modal passive: must + be + past participle.', ARRAY['b2','grammar']::text[]),
  ('dcfaca98-0cb5-4bb0-a965-3699cc6d73ac', '0a1d9f03-0af6-43af-89e4-58ecb5b48764', 'B2', 'grammar', 3, 'Hardly ___ the meeting started when the fire alarm rang.', '["had","did","has","was"]'::jsonb, 0, '''Hardly had... when'' is an inverted structure for a sequence of past events.', ARRAY['b2','grammar']::text[]),
  ('a70166a7-4164-419a-91bb-7641df774376', 'f0815856-a4e0-4c42-be79-8bde37c24fe7', 'C1', 'vocabulary', 4, 'His speech was so ___ that even experts struggled to follow his argument.', '["convoluted","lucid","succinct","candid"]'::jsonb, 0, '''Convoluted'' means extremely complex and difficult to follow.', ARRAY['c1','vocabulary']::text[]),
  ('7301c9d4-93b4-4c06-a89c-436506b67c79', '029f0917-f898-455d-a511-556ad2afc7a5', 'C1', 'vocabulary', 4, 'The critic praised the film for its ___ portrayal of war.', '["unflinching","superficial","glib","trivial"]'::jsonb, 0, '''Unflinching'' means not avoiding something difficult or unpleasant.', ARRAY['c1','vocabulary']::text[]),
  ('ec58bed7-a03b-43ed-b7ae-2bfe485b6278', '6abe66c1-31e9-4b1c-80cd-925d9c5a5597', 'C1', 'vocabulary', 4, 'Her ___ remarks during the meeting offended several colleagues.', '["tactless","diplomatic","gracious","courteous"]'::jsonb, 0, '''Tactless'' means lacking sensitivity in dealing with others.', ARRAY['c1','vocabulary']::text[]),
  ('7686937a-0ac9-4347-a175-afab07bf898d', '711e9e4a-a180-4156-9bc3-06347f23dbbc', 'C1', 'vocabulary', 4, 'The evidence was ___; no reasonable person could doubt his guilt.', '["incontrovertible","dubious","ambiguous","tenuous"]'::jsonb, 0, '''Incontrovertible'' means impossible to deny or dispute.', ARRAY['c1','vocabulary']::text[]),
  ('b882e6c8-275c-479e-827b-5daaf4af0261', 'd0be0ec5-49bd-4db9-962b-2f16cb5ff9f5', 'C1', 'vocabulary', 4, 'He has a ___ for exaggeration that makes his stories hard to believe.', '["propensity","reluctance","aversion","capacity"]'::jsonb, 0, '''Propensity'' means a natural tendency to behave in a particular way.', ARRAY['c1','vocabulary']::text[]),
  ('a4c09ddb-e178-4d3e-819a-aed233d4e1ca', 'b0c9a585-8ae7-408f-bf9e-138330d741ea', 'C1', 'phrasal_verb', 4, 'Tensions between the two countries finally ___ into open conflict.', '["boiled over","boiled up","boiled down","boiled out"]'::jsonb, 0, '''Boil over'' means a tense situation suddenly becomes an open conflict.', ARRAY['c1','phrasal_verb']::text[]),
  ('b9ec82f7-0fd7-4f81-b1f7-6099a077b5c4', 'cfd66b16-c169-4ba8-9cf3-d0a1aaacb955', 'C1', 'phrasal_verb', 4, 'Critics say the policy will only ___ the underlying problem rather than solve it.', '["paper over","paper out","paper down","paper up"]'::jsonb, 0, '''Paper over'' a problem means to hide it temporarily instead of solving it.', ARRAY['c1','phrasal_verb']::text[]),
  ('451032c4-8479-4ed9-b0d0-81df1083d0be', '3ef04310-a690-4d97-9c27-c3cbbdf8b53c', 'C1', 'phrasal_verb', 4, 'The board decided to ___ with the merger despite shareholder objections.', '["press ahead","press down","press out","press off"]'::jsonb, 0, '''Press ahead (with)'' means to continue determinedly.', ARRAY['c1','phrasal_verb']::text[]),
  ('c1cedfbe-1e2b-49c7-ad5f-fd8cb7a50465', '90a27e87-19e0-4bc8-85aa-5868427867bb', 'C1', 'phrasal_verb', 4, 'After the scandal, the senator struggled to ___ back public trust.', '["claw","pull","dig","hold"]'::jsonb, 0, '''Claw back'' means to gradually and with effort regain something lost.', ARRAY['c1','phrasal_verb']::text[]),
  ('888eec7b-aa35-41ed-845f-aebf5bf9e821', 'c7f9cc96-5839-4886-8c13-85e62464c6c2', 'C1', 'phrasal_verb', 4, 'The minister tried to ___ down speculation about a cabinet reshuffle.', '["play","push","hold","set"]'::jsonb, 0, '''Play down'' means to make something seem less important than it is.', ARRAY['c1','phrasal_verb']::text[]),
  ('24be8eb0-5f2b-4f3f-8fa0-615b6ecab030', 'aeb28752-20ea-44b8-a0d8-aee4678f853c', 'C1', 'collocation', 4, 'The government''s new policy has come under ___ fire from opposition parties.', '["heavy","strong","hard","big"]'::jsonb, 0, 'We say ''come under heavy fire'' (be strongly criticized).', ARRAY['c1','collocation']::text[]),
  ('b132f0b5-a1d6-44a1-b7d7-12e768918f77', '6d98dac5-4931-42bc-a9b9-7b3d1469b610', 'C1', 'collocation', 4, 'The committee reached a ___ decision after hours of debate.', '["unanimous","mutual","joint","common"]'::jsonb, 0, '''Unanimous decision'' means everyone agreed.', ARRAY['c1','collocation']::text[]),
  ('b2636bcb-5a2d-4662-a2d6-f7388e034453', '82b1a0ec-cb3e-48ab-b2c3-5acf42083dea', 'C1', 'collocation', 4, 'His proposal was met with ___ skepticism by the board.', '["widespread","large","big","much"]'::jsonb, 0, 'We say ''widespread skepticism/criticism''.', ARRAY['c1','collocation']::text[]),
  ('06200149-a4d5-47f8-9cdb-d4ad329b23da', 'fe042835-a85a-437f-ae41-83a16d29419d', 'C1', 'collocation', 4, 'The two companies are expected to ___ forces to compete with larger rivals.', '["join","make","do","take"]'::jsonb, 0, '''Join forces'' means to work together.', ARRAY['c1','collocation']::text[]),
  ('c46aed3e-3091-47b2-9e15-2b4d1f02c1d5', 'f88056b8-cc5f-4fb1-9f84-62da76df9149', 'C1', 'grammar', 4, '___ the heavy rain, the match went ahead as planned.', '["Despite","Although","Even though","In spite that"]'::jsonb, 0, '''Despite'' is followed by a noun phrase, not a clause.', ARRAY['c1','grammar']::text[]),
  ('de7efa3f-9138-4ab9-865f-be644e05537e', '54743f65-1932-41dd-98c5-f52db1c72461', 'C1', 'grammar', 4, 'Were it not for his support, the project ___ failed.', '["would have","will have","had","would"]'::jsonb, 0, 'Inverted third conditional: ''Were it not for X, ... would have + past participle''.', ARRAY['c1','grammar']::text[]),
  ('1cc91fae-4177-4b04-93dd-c928f75ad8a5', 'ad7dba6f-7aaa-4b27-81c8-91a19da8b0d1', 'C1', 'grammar', 4, 'It is essential that the report ___ submitted by Friday.', '["is","be","will be","was"]'::jsonb, 1, 'Subjunctive mood after ''essential that'': base form ''be'', no -s.', ARRAY['c1','grammar']::text[]),
  ('a96d1681-b035-4324-9bbf-b1f7bcf0896f', 'b2c20fc3-f156-4c7d-8ea7-b2f3aa254e88', 'C1', 'grammar', 4, 'Scarcely ___ the announcement been made when shares began to fall.', '["had","did","has","was"]'::jsonb, 0, '''Scarcely had... when'' is an inverted structure similar to ''hardly had''.', ARRAY['c1','grammar']::text[]),
  ('d68451de-26c0-4aca-a6a3-2103e7f3c516', '1f0747f2-9c73-4ff2-ab59-a53feaa7690c', 'C2', 'vocabulary', 5, 'His ___ for detail bordered on obsession.', '["predilection","aversion","indifference","disdain"]'::jsonb, 0, '''Predilection'' means a preference or special liking for something.', ARRAY['c2','vocabulary']::text[]),
  ('04a14451-9883-4d5d-8e51-386a92921bb7', 'd33f8d46-7fc7-4617-8af9-23e2261c4dac', 'C2', 'vocabulary', 5, 'The professor''s argument was ___ ; not a single point was open to dispute.', '["irrefutable","tenuous","spurious","fallacious"]'::jsonb, 0, '''Irrefutable'' means impossible to prove wrong.', ARRAY['c2','vocabulary']::text[]),
  ('7cedfd44-947e-4a4f-9ade-195b65814099', 'e42d3a82-222c-47bb-8fb3-e6f46da70c83', 'C2', 'vocabulary', 5, 'Her ___ wit made her the most entertaining person at the dinner.', '["scintillating","ponderous","insipid","turgid"]'::jsonb, 0, '''Scintillating'' means brilliantly clever and lively.', ARRAY['c2','vocabulary']::text[]),
  ('cf8a44a8-665e-4b8f-baea-04b040737d65', '04efbcf5-0cfd-4177-94c2-17230abe44f0', 'C2', 'vocabulary', 5, 'The negotiations were marked by a ___ of mutual distrust.', '["undercurrent","surplus","façade","semblance"]'::jsonb, 0, '''Undercurrent'' refers to a hidden feeling beneath the surface.', ARRAY['c2','vocabulary']::text[]),
  ('70b6faab-bf62-43e4-babf-02e76af00eeb', 'df895a0c-5eda-4fa7-a1fc-c1f4f265042c', 'C2', 'vocabulary', 5, 'He remained utterly ___ to their pleas for clemency.', '["impervious","susceptible","receptive","amenable"]'::jsonb, 0, '''Impervious'' means not affected or influenced by something.', ARRAY['c2','vocabulary']::text[]),
  ('0878933f-64fd-4ced-a28c-96db224c2ae0', '616ff38c-7e7e-4dab-a87b-51950a10fef9', 'C2', 'phrasal_verb', 5, 'Her offhand remark threatened to ___ up months of delicate negotiation.', '["muck","clean","set","take"]'::jsonb, 0, '''Muck up'' (informal) means to spoil or ruin something.', ARRAY['c2','phrasal_verb']::text[]),
  ('822d8e07-90c6-4695-8aaa-7777d2032a49', 'ba5fc91a-5bf3-49d6-a480-b906415a65fb', 'C2', 'phrasal_verb', 5, 'He has always managed to ___ on his natural charm rather than hard work.', '["trade","coast","bank","draw"]'::jsonb, 0, '''Trade on'' means to take advantage of something for personal benefit.', ARRAY['c2','phrasal_verb']::text[]),
  ('e5d40095-a0b2-4869-9543-497887de3497', '525d2c41-e841-4fb6-b785-721d610d5e70', 'C2', 'phrasal_verb', 5, 'The minister was forced to ___ down following the scandal.', '["step","sit","stand","fall"]'::jsonb, 0, '''Step down'' means to resign from a position.', ARRAY['c2','phrasal_verb']::text[]),
  ('69d23f66-859e-4bd2-9d54-85327f7110bc', '0002622a-a14b-4d42-b339-b581b1010a36', 'C2', 'phrasal_verb', 5, 'Years of pent-up frustration finally ___ over during the meeting.', '["boiled","poured","flowed","ran"]'::jsonb, 0, '''Boil over'' means suppressed emotion suddenly bursts out.', ARRAY['c2','phrasal_verb']::text[]),
  ('4a9c5f40-7a6b-40ab-be14-1b950caa66f5', 'c9fc945f-569e-44d4-81d9-9af87278b17c', 'C2', 'phrasal_verb', 5, 'She would not be ___ into revealing her sources.', '["browbeaten","ushered","ferried","steered"]'::jsonb, 0, '''Browbeaten into'' means forced through intimidation.', ARRAY['c2','phrasal_verb']::text[]),
  ('119f835b-e979-44e7-8cbd-29f1717d818f', 'c8f60035-4c4e-415a-924f-45027cc15c26', 'C2', 'collocation', 5, 'The findings ___ credence to the theory.', '["lend","give","make","take"]'::jsonb, 0, '''Lend credence to'' means to make something seem more believable.', ARRAY['c2','collocation']::text[]),
  ('731617b6-e40f-43ba-872b-ab36c96b61dd', '3ce7b6ae-ad48-4f6f-baf5-e44a8bd958ce', 'C2', 'collocation', 5, 'The two leaders finally found ___ ground after lengthy talks.', '["common","mutual","shared","joint"]'::jsonb, 0, '''Common ground'' means a shared basis for agreement.', ARRAY['c2','collocation']::text[]),
  ('b77a5e63-2674-49d2-9e3b-4ad146da934a', 'c470167a-7026-4476-b9cd-53e337a31061', 'C2', 'collocation', 5, 'His tactics drew ___ criticism from across the political spectrum.', '["scathing","heavy","big","strong"]'::jsonb, 0, '''Scathing criticism'' means severely critical.', ARRAY['c2','collocation']::text[]),
  ('a9e06459-333f-493d-9c6a-668eae497db0', 'fa2a6676-ed38-4ea4-ac16-807adebab3d4', 'C2', 'collocation', 5, 'The merger is expected to ___ significant synergies.', '["yield","make","do","take"]'::jsonb, 0, '''Yield'' means to produce or result in something.', ARRAY['c2','collocation']::text[]),
  ('67e40c1c-f515-4cf2-8f2a-ea76f4c44eaa', '6b1bd624-31dd-420e-8927-58059cd8b98c', 'C2', 'grammar', 5, 'Rarely ___ such unanimity been seen in parliament.', '["has","have","did","does"]'::jsonb, 0, 'Inversion with ''Rarely'' + has/have + past participle.', ARRAY['c2','grammar']::text[]),
  ('ddb78e91-f814-4fed-8f78-7cbaadfca35c', 'edb28145-ca17-485f-a271-f59d304219e7', 'C2', 'grammar', 5, '___ had she finished speaking than the audience erupted into applause.', '["No sooner","Hardly","Scarcely","Barely"]'::jsonb, 0, '''No sooner... than'' is the correct inverted pairing (not ''when'').', ARRAY['c2','grammar']::text[]),
  ('c1a03faa-9b92-4241-bbac-e1ef7e142fb4', 'af7b0dc5-e4e7-4c3e-81c9-252ccffcf4a6', 'C2', 'grammar', 5, 'It was not until much later ___ the truth came to light.', '["that","when","then","which"]'::jsonb, 0, 'Cleft sentence: ''It was not until... that...''.', ARRAY['c2','grammar']::text[]),
  ('2a37c6a8-4f22-4ead-9644-8ae144423cbc', '582b193d-e14f-4ee7-bdea-772423ae8496', 'C2', 'grammar', 5, 'Had the committee ___ the warnings, the crisis might have been averted.', '["heeded","heed","heeding","to heed"]'::jsonb, 0, 'Inverted third conditional: ''Had + subject + past participle...''.', ARRAY['c2','grammar']::text[]);
