-- Word Survivor content tables: terms (vocabulary/phrasal verbs/collocations/grammar points)
-- and the questions that test them. Replaces the hardcoded question bank so content can be
-- managed from the admin panel without code changes.

CREATE TABLE public.word_survivor_terms (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  term text NOT NULL,
  meaning text NOT NULL,
  example_sentence text,
  level text NOT NULL CHECK (level IN ('A1','A2','B1','B2','C1','C2')),
  type text NOT NULL CHECK (type IN ('vocabulary','phrasal_verb','collocation','grammar','listening','cambridge')),
  created_at timestamptz NOT NULL DEFAULT now(),
  UNIQUE (term, level, type)
);

CREATE TABLE public.word_survivor_questions (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  term_id uuid NOT NULL REFERENCES public.word_survivor_terms(id) ON DELETE CASCADE,
  level text NOT NULL CHECK (level IN ('A1','A2','B1','B2','C1','C2')),
  type text NOT NULL CHECK (type IN ('vocabulary','phrasal_verb','collocation','grammar','listening','cambridge')),
  difficulty smallint NOT NULL DEFAULT 1 CHECK (difficulty BETWEEN 1 AND 5),
  prompt text NOT NULL,
  options jsonb NOT NULL,
  correct_index smallint NOT NULL,
  tip text,
  tags text[] NOT NULL DEFAULT '{}',
  audio_url text,
  active boolean NOT NULL DEFAULT true,
  created_by uuid REFERENCES public.usuarios(id),
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX idx_word_survivor_questions_level ON public.word_survivor_questions (level);
CREATE INDEX idx_word_survivor_questions_active ON public.word_survivor_questions (active);
CREATE INDEX idx_word_survivor_questions_term_id ON public.word_survivor_questions (term_id);

ALTER TABLE public.word_survivor_terms ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.word_survivor_questions ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Terminos visibles para usuarios autenticados"
ON public.word_survivor_terms
FOR SELECT
USING (auth.role() = 'authenticated');

CREATE POLICY "Admin gestiona terminos"
ON public.word_survivor_terms FOR ALL TO authenticated
USING (has_role(auth.uid(), 'admin'::app_role) OR has_role(auth.uid(), 'content_admin'::app_role))
WITH CHECK (has_role(auth.uid(), 'admin'::app_role) OR has_role(auth.uid(), 'content_admin'::app_role));

CREATE POLICY "Preguntas activas visibles para usuarios autenticados"
ON public.word_survivor_questions
FOR SELECT
USING (auth.role() = 'authenticated' AND active = true);

CREATE POLICY "Admin gestiona preguntas"
ON public.word_survivor_questions FOR ALL TO authenticated
USING (has_role(auth.uid(), 'admin'::app_role) OR has_role(auth.uid(), 'content_admin'::app_role))
WITH CHECK (has_role(auth.uid(), 'admin'::app_role) OR has_role(auth.uid(), 'content_admin'::app_role));

-- Seed data migrated from the original hardcoded question bank (108 questions, A1-C2).

